from flask import Flask, request, jsonify
from src.task_queue import TaskQueue
import pickle
import base64


def create_app(queue=None):
    app = Flask(__name__)
    if queue is None:
        queue = TaskQueue()
    app.queue = queue

    @app.post("/tasks")
    def submit_task():
        data = request.get_json(silent=True) or {}
        # Accept a serialized callable via base64-encoded pickle, or a simple echo value
        if "fn_b64" in data:
            task_fn = pickle.loads(base64.b64decode(data["fn_b64"]))
        elif "value" in data:
            value = data["value"]
            task_fn = lambda: value
        else:
            return jsonify({"error": "provide 'value' or 'fn_b64'"}), 400
        priority = data.get("priority", 0)
        task_id = app.queue.submit(task_fn, priority=priority)
        return jsonify({"task_id": task_id}), 201

    @app.get("/tasks/<task_id>")
    def get_task(task_id):
        status = app.queue.get_status(task_id)
        if status is None:
            return jsonify({"error": "not found"}), 404
        return jsonify({"task_id": task_id, **status})

    @app.get("/tasks")
    def list_tasks():
        tasks = app.queue.list_tasks()
        return jsonify([{"task_id": tid, **info} for tid, info in tasks.items()])

    return app

